import { headers } from "next/headers";
// 👇 CHECK THIS PATH: If you moved 'lib' to 'src/lib', change this to "@/lib/supabase/server"
import { createClient } from "@/app/lib/supabase/server"; 
import { redirect } from "next/navigation";

export default async function Login({
  searchParams,
}: {
  searchParams: Promise<{ message: string }>;
}) {
  const { message } = await searchParams;

  const signIn = async (formData: FormData) => {
    "use server";
    
    const email = (formData.get("email") as string) || "";
    const password = (formData.get("password") as string) || "";
    const supabase = await createClient();

    // 1. Attempt Login
    const { error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    // 2. Handle Error
    if (error) {
      console.error("SignIn error", error);
      return redirect(`/login?message=${encodeURIComponent(error.message ?? "Sign in failed")}`);
    }

    // 3. Success Redirect (MUST BE OUTSIDE try/catch)
    return redirect("/");
  };

  const signUp = async (formData: FormData) => {
    "use server";
    
    // Fix headers awaiting for Next.js 15
    const hdr = await headers();
    const origin = hdr.get("origin") ?? `http://localhost:${process.env.PORT ?? 3000}`;

    const email = (formData.get("email") as string) || "";
    const password = (formData.get("password") as string) || "";
    const supabase = await createClient();

    // 1. Attempt Sign Up
    const { error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: `${origin}/auth/callback`,
      },
    });

    // 2. Handle Error
    if (error) {
      console.error("SignUp error", error);
      return redirect(`/login?message=${encodeURIComponent(error.message ?? "Sign up failed")}`);
    }

    // 3. Success Redirect
    return redirect("/login?message=Check email to continue sign in process");
  };

  return (
    <div className="flex-1 flex flex-col w-full px-8 sm:max-w-md justify-center gap-2 mx-auto mt-20">
      <form
        className="animate-in flex-1 flex flex-col w-full justify-center gap-2 text-foreground"
        action={signIn}
      >
        <label className="text-md" htmlFor="email">Email</label>
        <input
          className="rounded-md px-4 py-2 bg-inherit border mb-6"
          name="email"
          placeholder="you@example.com"
          required
        />
        <label className="text-md" htmlFor="password">Password</label>
        <input
          className="rounded-md px-4 py-2 bg-inherit border mb-6"
          type="password"
          name="password"
          placeholder="••••••••"
          required
        />
        <button className="bg-green-700 rounded-md px-4 py-2 text-foreground mb-2 text-white">
          Sign In
        </button>
        <button
          formAction={signUp}
          className="border border-foreground/20 rounded-md px-4 py-2 text-foreground mb-2"
        >
          Sign Up
        </button>
        
        {message && (
          <p className="mt-4 p-4 bg-foreground/10 text-foreground text-center">
            {message}
          </p>
        )}
      </form>
    </div>
  );
}